420→/** @internal Exported for testing only */
421→export function spawnAsync(
422→  command: string,
423→  args: string[],
424→  options: SpawnOptions,
425→): Promise<SpawnResult> {
426→  return new Promise((resolve, reject) => {
427→    let stdout = "";
428→    let stderr = "";
429→    let settled = false;
430→
431→    const proc = spawn(command, args, {
432→      stdio: ["pipe", "pipe", "pipe"],
433→      env: options.env,
434→      detached: true,
435→    });
436→
437→    const settle = (
438→      outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
439→    ) => {
440→      if (settled) return;
441→      settled = true;
442→      clearTimeout(timeoutId);
443→      options.signal?.removeEventListener("abort", onAbort);
444→      if (outcome.ok) {
445→        resolve(outcome.result);
446→      } else {
447→        reject(outcome.error);
448→      }
449→    };
450→
451→    const timeoutId = setTimeout(() => {
452→      killProcessGroup(proc);
453→      settle({
454→        ok: false,
455→        error: new Error(`Process timed out after ${options.timeout}ms`),
456→      });
457→    }, options.timeout);
458→
459→    const onAbort = () => {
460→      killProcessGroup(proc);
461→      settle({ ok: false, error: new Error("Cancelled by client") });
462→    };
463→
464→    if (options.signal) {
465→      if (options.signal.aborted) {
466→        killProcessGroup(proc);
467→        clearTimeout(timeoutId);
468→        reject(new Error("Cancelled by client"));
469→        return;
470→      }
471→      options.signal.addEventListener("abort", onAbort, { once: true });
472→    }
473→
474→    proc.stdout.on("data", (data: Buffer) => {
475→      stdout += data.toString();
476→    });
477→
478→    proc.stderr.on("data", (data: Buffer) => {
479→      stderr += data.toString();
480→    });
481→
482→    proc.on("error", (err: NodeJS.ErrnoException) => {
483→      if (err.code === "ENOENT") {
484→        settle({
485→          ok: false,
486→          error: new Error(
487→            `Command not found: ${command}. Ensure it is installed and in PATH.`,
488→          ),
489→        });
490→      } else {
491→        settle({
492→          ok: false,
493→          error: new Error(`Failed to spawn process: ${err.message}`),
494→        });
495→      }
496→    });
497→
498→    proc.on("close", (code: number | null) => {
499→      settle({ ok: true, result: { exitCode: code, stdout, stderr } });
500→    });
501→  });
502→}
503→
504→const SIGKILL_GRACE_MS = 5000;
505→
506→function killProcessGroup(proc: ReturnType<typeof spawn>): void {
507→  let exited = false;
508→  proc.on("close", () => {
509→    exited = true;
510→  });
511→
512→  sendSignal(proc, "SIGTERM");
513→
514→  setTimeout(() => {
515→    if (!exited) {
516→      sendSignal(proc, "SIGKILL");
517→    }
518→  }, SIGKILL_GRACE_MS).unref();
519→}
520→
521→function sendSignal(
522→  proc: ReturnType<typeof spawn>,
523→  signal: NodeJS.Signals,
524→): void {
525→  try {
526→    if (proc.pid) {
527→      process.kill(-proc.pid, signal);
528→    }
529→  } catch {
530→    // Process group may already be gone — fall back to direct kill
531→    if (!proc.killed) {
532→      proc.kill(signal);
533→    }
534→  }
535→}
