  it("should handle single issue run", () => {
    const runLog = makeRunLog({
      issues: [
        {
          issueNumber: 42,
          title: "Single issue",
          labels: [],
          status: "success",
          phases: [
            {
              phase: "exec",
              issueNumber: 42,
              startTime: "2026-03-23T10:00:00.000Z",
              endTime: "2026-03-23T10:01:00.000Z",
              durationSeconds: 60,
              status: "success",
            },
          ],
          totalDurationSeconds: 60,
        },
      ],
      summary: {
        totalIssues: 1,
        passed: 1,
        failed: 0,
        totalDurationSeconds: 60,
      },
    });
