/**
 * Build a fallback response when no log file is available
 */
function buildFallbackResponse(
  stdout: string,
  issueNumbers: number[],
  overallStatus: "success" | "failure",
  phases: string,
  exitCode?: number | null,
  stderr?: string,
): RunToolResponse {
  return {
