          response = buildFallbackResponse(
            stdout,
            issues,
            overallStatus,
            phasesStr,
            result.exitCode,
            stderr || undefined,
          );
        }

        return {
          content: [
            {
              type: "text" as const,
              text: JSON.stringify(response),
            },
          ],
          ...(result.exitCode !== 0 ? { isError: true } : {}),
        };
      } catch (error) {
        return {
          content: [
            {
              type: "text" as const,
              text: JSON.stringify({
                error: "EXECUTION_ERROR",
                message: error instanceof Error ? error.message : String(error),
              }),
            },
          ],
          isError: true,
        };
      }
    }) as Parameters<typeof server.registerTool>[2],
  );
}

export interface SpawnResult {
  exitCode: number | null;
  stdout: string;
  stderr: string;
}

export interface SpawnOptions {
  timeout: number;
  env?: NodeJS.ProcessEnv;
  signal?: AbortSignal;
}

/** @internal Exported for testing only */
export function spawnAsync(
  command: string,
  args: string[],
  options: SpawnOptions,
): Promise<SpawnResult> {
  return new Promise((resolve, reject) => {
    let stdout = "";
    let stderr = "";
    let settled = false;

    const proc = spawn(command, args, {
      stdio: ["pipe", "pipe", "pipe"],
      env: options.env,
      detached: true,
    });

    const settle = (
      outcome: { ok: true; result: SpawnResult } | { ok: false; error: Error },
    ) => {
      if (settled) return;
      settled = true;
      clearTimeout(timeoutId);
      options.signal?.removeEventListener("abort", onAbort);
      if (outcome.ok) {
        resolve(outcome.result);
      } else {
        reject(outcome.error);
      }
    };

    const timeoutId = setTimeout(() => {
      killProcessGroup(proc);
      settle({
        ok: false,
        error: new Error(`Process timed out after ${options.timeout}ms`),
      });
    }, options.timeout);

    const onAbort = () => {
      killProcessGroup(proc);
      settle({ ok: false, error: new Error("Cancelled by client") });
    };

    if (options.signal) {
      if (options.signal.aborted) {
        killProcessGroup(proc);
        clearTimeout(timeoutId);
        reject(new Error("Cancelled by client"));
        return;
      }
      options.signal.addEventListener("abort", onAbort, { once: true });
    }

    proc.stdout.on("data", (data: Buffer) => {
      stdout += data.toString();
    });

    proc.stderr.on("data", (data: Buffer) => {
      stderr += data.toString();
    });

    proc.on("error", (err: NodeJS.ErrnoException) => {
      if (err.code === "ENOENT") {
        settle({
          ok: false,
          error: new Error(
            `Command not found: ${command}. Ensure it is installed and in PATH.`,
          ),
        });
      } else {
        settle({
          ok: false,
          error: new Error(`Failed to spawn process: ${err.message}`),
        });
      }
    });

    proc.on("close", (code: number | null) => {
      settle({ ok: true, result: { exitCode: code, stdout, stderr } });
    });
  });
}

const SIGKILL_GRACE_MS = 5000;

function killProcessGroup(proc: ReturnType<typeof spawn>): void {
  let exited = false;
  proc.on("close", () => {
    exited = true;
  });

  sendSignal(proc, "SIGTERM");

  setTimeout(() => {
    if (!exited) {
      sendSignal(proc, "SIGKILL");
    }
  }, SIGKILL_GRACE_MS).unref();
}

function sendSignal(
  proc: ReturnType<typeof spawn>,
  signal: NodeJS.Signals,
): void {
  try {
    if (proc.pid) {
      process.kill(-proc.pid, signal);
    }
  } catch {
    // Process group may already be gone — fall back to direct kill
    if (!proc.killed) {
      proc.kill(signal);
    }
  }
}

